- (void)handleShortcutItem:(UIApplicationShortcutItem *)shortcutItem {
    NSString *contactSupport = [[[NSBundle mainBundle] bundleIdentifier] stringByAppendingString:@".contactSupport"];
    NSString *modifySettings = [[[NSBundle mainBundle] bundleIdentifier] stringByAppendingString:@".modifySettings"];
    if ([shortcutItem.type isEqualToString:contactSupport]) {
        dispatch_async(dispatch_get_main_queue(), ^{
            UINavigationController *targetNavController = nil;
            UITabBarController *tabBarController = (UITabBarController *)self;
            UIViewController *selectedVC = tabBarController.selectedViewController;
            if ([selectedVC isKindOfClass:[UINavigationController class]]) {
                targetNavController = (UINavigationController *)selectedVC;
            } else if (selectedVC.navigationController) {
                targetNavController = selectedVC.navigationController;
            }

            if (!targetNavController) {
                return;
            }

            // 避免重复推入相同的页面
            if ([targetNavController.topViewController isKindOfClass:[FeedbackViewController class]]) {
                return;
            }

            FeedbackViewController *feedbackVC = [[FeedbackViewController alloc] init];
            feedbackVC.hidesBottomBarWhenPushed = YES; // 隐藏底部标签栏
            [targetNavController pushViewController:feedbackVC animated:YES];
        });
    } else if ([shortcutItem.type isEqualToString:modifySettings]) {
        dispatch_async(dispatch_get_main_queue(), ^{
            UINavigationController *targetNavController = nil;
            UITabBarController *tabBarController = (UITabBarController *)self;
            UIViewController *selectedVC = tabBarController.selectedViewController;
            if ([selectedVC isKindOfClass:[UINavigationController class]]) {
                targetNavController = (UINavigationController *)selectedVC;
            } else if (selectedVC.navigationController) {
                targetNavController = selectedVC.navigationController;
            }

            if (!targetNavController) {
                return;
            }

            // 避免重复推入相同的页面
            if ([targetNavController.topViewController isKindOfClass:[FeedbackViewController class]]) {
                return;
            }

            SettingViewController *SettingVC = [[SettingViewController alloc] init];
            SettingVC.hidesBottomBarWhenPushed = YES; // 隐藏底部标签栏
            [targetNavController pushViewController:SettingVC animated:YES];
        });
    }
}


