    NSLog(@"加载失败: %@", error.localizedDescription);

    // 地区限制检测
    if (error.code == NSURLErrorNotConnectedToInternet ||
        error.code == NSURLErrorTimedOut) {
        [self _showAlertWithTitle:@"Connection Issue"
                         message:@"\nPlease check network connection"];
    } else {
        [self _showAlertWithTitle:@"Access Restricted"
                         message:@"Service unavailable in your region, try VPN"];
    }

}

