}

+ (void)saveMessageNum:(NSInteger)messagenum {
    [[NSUserDefaults standardUserDefaults] setInteger:messagenum forKey:@"AIChatListMessageModel.messagenum"];
    [[NSUserDefaults standardUserDefaults] synchronize];
}

