#pragma mark - input & send

- (void)textfieldEditingChanged:(UITextField *)textField {
    NSString *trimmed = [textField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    BOOL hasText = trimmed.length > 0;
    self.sendButton.enabled = hasText;
    self.sendButton.backgroundColor = hasText ? RGBA(135, 127, 233, 1) : RGB(203, 203, 203);
}

- (void)handleSend {
    NSString *trimmed = [self.textfield.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    if (trimmed.length == 0) {
        return;
    }
    // 停止当前朗读与节流
    if (self.speechSynthesizer.isSpeaking) {
        [self.speechSynthesizer stopSpeakingAtBoundary:AVSpeechBoundaryImmediate];
    }
    if (self.speechDebounceTimer) {
        [self.speechDebounceTimer invalidate];
        self.speechDebounceTimer = nil;
    }
    // 追加用户消息
    AIChatListMessageModel *userMsg = [[AIChatListMessageModel alloc] initWithText:trimmed time:[NSDate date] type:AIChatListMessageTypeSent context:@"" Done:NO];
    [self.messages addObject:userMsg];
    NSIndexPath *userPath = [NSIndexPath indexPathForRow:self.messages.count - 1 inSection:0];
    self.textfield.text = @"";
    self.sendButton.enabled = NO;
    self.sendButton.backgroundColor = RGB(203, 203, 203);
    [self.tableView beginUpdates];
    [self.tableView insertRowsAtIndexPaths:@[userPath] withRowAnimation:UITableViewRowAnimationAutomatic];
    [self.tableView endUpdates];
    [self scrollToBottom];
    [AIChatListStorage saveMessages:self.messages forChatId:self.chatId];

    // 追加 AI 占位消息
    AIChatListMessageModel *aiPlaceholder = [[AIChatListMessageModel alloc] initWithText:@"" time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO];
    [self.messages addObject:aiPlaceholder];
    self.hasSpokenCurrentAI = NO;
    self.lastSpokenIndex = 0;
    self.speakingMessageRow = self.messages.count - 1;
    NSIndexPath *aiPath = [NSIndexPath indexPathForRow:self.messages.count - 1 inSection:0];
    [self.tableView beginUpdates];
    [self.tableView insertRowsAtIndexPaths:@[aiPath] withRowAnimation:UITableViewRowAnimationAutomatic];
    [self.tableView endUpdates];
    [self scrollToBottom];
    [AIChatListStorage saveMessages:self.messages forChatId:self.chatId];

    // 启动输入中动画
    [self stopTypingIndicator]; // 先清理
    self.typingStep = 0;
    [self startTypingIndicator];

    // AI 服务回调
    AIChatListServerManager *mgr = [AIChatListServerManager sharedManager];
    __weak typeof(self) weakSelf = self;
    mgr.onPartialUpdate = ^(NSString *partialText) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;
        if (partialText.length > 0) {
            [self stopTypingIndicator];
            if (self.voiceEnabled) {
                [self enqueueClosedSentencesForLatestAI];
            }
        }
        NSIndexPath *last = [NSIndexPath indexPathForRow:self.messages.count - 1 inSection:0];
        [self.tableView reloadRowsAtIndexPaths:@[last] withRowAnimation:UITableViewRowAnimationNone];
        [self scrollToBottom];
    };
    mgr.onDoneUpdate = ^(NSArray *context, NSString *finalText) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;
        [self stopTypingIndicator];
        if (self.voiceEnabled) {
            self.speakingMessageRow = self.messages.count - 1;
            if (self.speechDebounceTimer) {
                [self.speechDebounceTimer invalidate];
                self.speechDebounceTimer = nil;
            }
            [self enqueueClosedSentencesForLatestAI];
            if (finalText.length > self.lastSpokenIndex) {
                NSString *tail = [finalText substringFromIndex:self.lastSpokenIndex];
                NSString *lang = [self isChineseText:tail] ? @"zh-CN" : @"en-US";
                [self enqueueSpeakText:tail language:lang];
                self.lastSpokenIndex = finalText.length;
            }
        }
        NSIndexPath *last = [NSIndexPath indexPathForRow:self.messages.count - 1 inSection:0];
        [self.tableView reloadRowsAtIndexPaths:@[last] withRowAnimation:UITableViewRowAnimationNone];
        [self scrollToBottom];
        self.sendButton.enabled = NO;
        self.sendButton.backgroundColor = RGB(203, 203, 203);
        [AIChatListStorage saveMessages:self.messages forChatId:self.chatId];
    };

    // 语言提示：提示语统一为英文（保持语义：中文问题→用中文回答）
    NSString *payloadText = trimmed;
    if ([self isChineseText:trimmed]) {
        payloadText = [NSString stringWithFormat:@"%@\n(Please respond in Chinese.)", trimmed];
    } else {
        payloadText = [NSString stringWithFormat:@"%@\n(Please respond in English.)", trimmed];
    }
    [[AIChatListServerManager sharedManager] sendPOSTRequestAndHandleStreamResponse:payloadText belongMessages:self.messages];
}

#pragma mark - Typing Indicator

- (void)startTypingIndicator {
    if (self.typingTimer) {
        [self.typingTimer invalidate];
        self.typingTimer = nil;
    }
    __weak typeof(self) weakSelf = self;
    self.typingTimer = [NSTimer scheduledTimerWithTimeInterval:0.6 repeats:YES block:^(NSTimer * _Nonnull timer) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;
        [self updateTypingIndicator];
    }];
}

- (void)stopTypingIndicator {
    if (self.typingTimer) {
        [self.typingTimer invalidate];
        self.typingTimer = nil;
    }
}

- (void)updateTypingIndicator {
    if (self.messages.count == 0) return;
    AIChatListMessageModel *last = [self.messages lastObject];
    if (last.type != AIChatListMessageTypeReceived || last.done) {
        [self stopTypingIndicator];
        return;
    }
    self.typingStep = (self.typingStep + 1) % 3;
    switch (self.typingStep) {
        case 0: last.text = @"."; break;
        case 1: last.text = @".."; break;
        default: last.text = @"..."; break;
    }
    NSIndexPath *lastPath = [NSIndexPath indexPathForRow:self.messages.count - 1 inSection:0];
    [self.tableView reloadRowsAtIndexPaths:@[lastPath] withRowAnimation:UITableViewRowAnimationNone];
    [self scrollToBottom];
}

