- (void)speakMessageText:(NSString *)text {
    if (text.length == 0) return;
    if (self.speechSynthesizer.isSpeaking) {
        [self.speechSynthesizer stopSpeakingAtBoundary:AVSpeechBoundaryImmediate];
    }
    AVAudioSession *session = [AVAudioSession sharedInstance];
    NSError *sessionError = nil;
    [session setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionDuckOthers error:&sessionError];
    [session setActive:YES error:&sessionError];
    NSString *lang = [self isChineseText:text] ? @"zh-CN" : @"en-US";
    NSArray<NSString *> *chunks = [self chunkTextForUtterances:text];
    CGFloat baseRate = AVSpeechUtteranceDefaultSpeechRate;
    CGFloat rate = (text.length > 200) ? MAX(0.4, baseRate - 0.05) : baseRate;
    for (NSString *chunk in chunks) {
        AVSpeechUtterance *utt = [AVSpeechUtterance speechUtteranceWithString:chunk];
        utt.voice = [AVSpeechSynthesisVoice voiceWithLanguage:lang];
        utt.rate = rate;
        utt.pitchMultiplier = 1.0;
        utt.volume = 1.0;
        utt.postUtteranceDelay = 0.05;
        [self.speechSynthesizer speakUtterance:utt];
    }
}

- (void)enqueueSpeakText:(NSString *)text language:(NSString *)lang {
    if (text.length == 0) return;
