@interface CustomerServiceViewController () <UITableViewDelegate, UITableViewDataSource, UITextFieldDelegate, UIGestureRecognizerDelegate, UINavigationControllerDelegate, UIImagePickerControllerDelegate>

@property (nonatomic, strong) UITableView *chatTableView;
@property (nonatomic, strong) NSMutableArray<CustomerServiceMessageModel *> *messages;
@property (nonatomic, strong) CustomerServiceInputView *sendView;
@property (nonatomic, strong) UIImage *previewImage;
@property (nonatomic, strong) UIViewController *imagePreviewController;
@property (nonatomic, assign) BOOL isLoadingOlder;
@property (nonatomic, assign) BOOL hasMoreHistory;
@property (nonatomic, assign) BOOL didInitialBottomScroll;

@end

@implementation CustomerServiceViewController

- (void)viewDidLoad {
    [super viewDidLoad];
    self.title = @"Support";
    UIImage *backImg = [UIImage imageNamed:@"A_back"];
    if (backImg) {
        UIImage *returnImage = [[backImg imageByResizeToSize:CGSizeMake(ZOOM(24), ZOOM(24)) contentMode:UIViewContentModeScaleAspectFit] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
        self.navigationItem.leftBarButtonItem = [[UIBarButtonItem alloc] initWithImage:returnImage style:UIBarButtonItemStylePlain target:self action:@selector(returnButtonClicked)];
    }

    // 点击空白收起键盘
    UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(handleTap)];
    tapGesture.cancelsTouchesInView = NO; // 不取消其他触摸事件
    tapGesture.delegate = self;
    [self.view addGestureRecognizer:tapGesture];

    // 键盘通知
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillShow:) name:UIKeyboardWillShowNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillHide:) name:UIKeyboardWillHideNotification object:nil];

#if ENABLE_FEEDBACK

    self.messages = [NSMutableArray array];
    self.hasMoreHistory = YES;
    [self refreshFeedbacks];

#else

    self.messages = [CustomerServiceMessageModel allMsgs];
    if ([CustomerServiceMessageModel allMsgs].count == 0) {
        NSString *welcome = @"Hello, I am your dedicated customer service representative. Feel free to ask me any questions and I will answer them one by one.";
        CustomerServiceMessageModel *welcomeMsg = [[CustomerServiceMessageModel alloc] initWithContent:welcome isSend:NO];
        [CustomerServiceMessageModel addMsg:welcomeMsg];
    }

#endif

    [self setupUI];
}

- (void)viewDidLayoutSubviews {
    [super viewDidLayoutSubviews];
    if (!self.didInitialBottomScroll && self.messages.count > 0) {
        self.didInitialBottomScroll = YES;
        [self ensureBottomVisibleWithRetries:4 animated:NO];
    }
}

- (void)viewDidAppear:(BOOL)animated {
    [super viewDidAppear:animated];
    if (self.messages.count > 0) {
        [self ensureBottomVisibleWithRetries:4 animated:NO];
    }
}

- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}


#pragma mark - setupUI

- (void)setupUI {
    [self addAllSubviews];
    [self addAllConstraints];
}

- (void)addAllSubviews {
    [self.view addSubview:self.chatTableView];
    [self.view addSubview:self.sendView];
}

- (void)addAllConstraints {
    [_chatTableView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view);
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.sendView.mas_top);
    }];
    [_sendView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.height.mas_equalTo(ZOOMW(88));
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.view);
    }];
}


#pragma mark - Load Data

#if ENABLE_FEEDBACK

- (void)refreshFeedbacks {
    NSInteger fromId = 0;
    [[CustomerServiceManager sharedManager] fetchRecentFeedbacksWithCount:15 from:fromId completion:^(NSArray<CustomerServiceMessageModel *> * _Nullable feedbacks, NSError * _Nullable error) {
        if (error) {
            NSString *errorDescription = [NSString stringWithFormat:@"Load failed: %@", error.localizedDescription ?: @""];
            [SVProgressHUD showErrorWithStatus:errorDescription];
            return;
        }
        if (feedbacks.count > 0) {
            [self.messages addObjectsFromArray:feedbacks];
            [self.chatTableView reloadData];
            dispatch_async(dispatch_get_main_queue(), ^{
                [self ensureBottomVisibleWithRetries:5 animated:NO];
            });
        }
        [self startPullNewFeedbackWithAutomaticFrequency];
    }];
}

- (void)startPullNewFeedbackWithAutomaticFrequency {
    [self pullNewFeedbackWithAutomaticFrequency];
}

- (void)pullNewFeedbackWithAutomaticFrequency {
    NSParameterAssert([[NSOperationQueue currentQueue] isEqual:[NSOperationQueue mainQueue]]);
    [self pullNewFeedback];
    NSString *latestString = [self.messages lastObject].time;
    NSDate *latestDate = [self dateFromString:latestString];
    NSTimeInterval latestInterval = latestDate ? [[NSDate date] timeIntervalSinceDate:latestDate] : 0.0f;
    NSTimeInterval nextPullInterval = 0.0f;
    if (latestInterval < 60.0f) {
        nextPullInterval = 1.0f;
    } else if (latestInterval < 60.0f * 10) {
        nextPullInterval = 3.0f;
    } else if (latestInterval < 60.0f * 60) {
        nextPullInterval = 5.0f;
    } else {
        nextPullInterval = 10.0f;
    }
    __weak typeof(self) weakSelf = self;
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(nextPullInterval * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        [weakSelf pullNewFeedbackWithAutomaticFrequency];
    });
}

- (void)pullNewFeedback {
    [[CustomerServiceManager sharedManager] pullLatestFeedbacksWithCount:NSIntegerMax completion:^(NSArray<CustomerServiceMessageModel *> * _Nullable feedbacks, NSError * _Nullable error) {
        if (error) {
            NSLog(@"轮询客服最新消息失败：%@", error.localizedDescription);
            return;
        }
        if (feedbacks.count == 0) { return; }
        NSInteger startIndex = self.messages.count;
        [self.messages addObjectsFromArray:feedbacks];
        NSMutableArray<NSIndexPath *> *paths = [NSMutableArray arrayWithCapacity:feedbacks.count];
        for (NSInteger i = 0; i < feedbacks.count; i++) {
            [paths addObject:[NSIndexPath indexPathForRow:startIndex + i inSection:0]];
        }
        [self.chatTableView performBatchUpdates:^{
            [self.chatTableView insertRowsAtIndexPaths:paths withRowAnimation:UITableViewRowAnimationNone];
        } completion:^(BOOL finished) {
            [self ensureBottomVisibleWithRetries:5 animated:NO];
        }];
    }];
}

- (void)loadOlderIfNeeded {
    if (self.isLoadingOlder || !self.hasMoreHistory) { return; }
    CGFloat y = self.chatTableView.contentOffset.y;
    if (y > 0) { return; }
    [self loadOlderMessages];
}

- (void)loadOlderMessages {
    self.isLoadingOlder = YES;
    NSInteger fromId = self.messages.count > 0 ? self.messages.firstObject.msgId : 0;
    CGFloat beforeHeight = self.chatTableView.contentSize.height;
    [[CustomerServiceManager sharedManager] fetchRecentFeedbacksWithCount:10 from:fromId completion:^(NSArray<CustomerServiceMessageModel *> * _Nullable feedbacks, NSError * _Nullable error) {
        self.isLoadingOlder = NO;
        if (error) { return; }
        if (feedbacks.count == 0) { self.hasMoreHistory = NO; return; }
        NSSet *existing = [NSSet setWithArray:[self.messages valueForKey:@"msgId"]];
        NSMutableArray<CustomerServiceMessageModel *> *toInsert = [NSMutableArray array];
        for (CustomerServiceMessageModel *m in feedbacks) {
            if (![existing containsObject:@(m.msgId)]) {
                [toInsert addObject:m];
            }
        }
        if (toInsert.count == 0) { return; }
        NSArray<CustomerServiceMessageModel *> *sorted = [toInsert sortedArrayUsingComparator:^NSComparisonResult(CustomerServiceMessageModel * _Nonnull a, CustomerServiceMessageModel * _Nonnull b) {
            if (a.msgId < b.msgId) return NSOrderedAscending;
            if (a.msgId > b.msgId) return NSOrderedDescending;
            return NSOrderedSame;
        }];
        NSIndexSet *indexes = [NSIndexSet indexSetWithIndexesInRange:NSMakeRange(0, sorted.count)];
        [self.messages insertObjects:sorted atIndexes:indexes];
        [self.chatTableView reloadData];
        CGFloat afterHeight = self.chatTableView.contentSize.height;
        CGFloat delta = afterHeight - beforeHeight;
        CGPoint offset = self.chatTableView.contentOffset;
        offset.y += delta;
        [self.chatTableView setContentOffset:offset animated:NO];
    }];
}

- (NSDate *)dateFromString:(NSString *)s {
    if (![s isKindOfClass:NSString.class] || s.length == 0) {
        return nil;
    }
    static NSDateFormatter *fmt;
    static dispatch_once_t once;
    dispatch_once(&once, ^{
        fmt = [[NSDateFormatter alloc] init];
        fmt.locale = [NSLocale localeWithLocaleIdentifier:@"en_US_POSIX"];
        NSTimeZone *tz = [NSTimeZone timeZoneWithName:@"Asia/Shanghai"];
        fmt.timeZone = tz ?: [NSTimeZone timeZoneForSecondsFromGMT:8*3600];
        fmt.dateFormat = @"yyyy-MM-dd HH:mm:ss";
    });
    return [fmt dateFromString:s];
}

#endif


#pragma mark - events

- (void)returnButtonClicked {
    [self.navigationController popViewControllerAnimated:YES];
}

- (void)handleTap {
    [self.view endEditing:YES];
}

- (void)textfieldEditingChanged:(UITextField *)textField {
    NSString *trimmed = [textField.text stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    BOOL hasText = trimmed.length > 0;
    self.sendView.sendButton.enabled = hasText;
    self.sendView.sendButton.alpha = hasText ? 1.0 : 0.6;
}

- (void)send:(UIButton *)sender {
    NSString *userText = self.sendView.sendTextField.text;
    if (userText.length == 0) return;

#if ENABLE_FEEDBACK

    [CustomerServiceManager.sharedManager sendFeedbackText:userText completion:^(NSArray<CustomerServiceMessageModel *> * _Nullable feedbacks, NSError * _Nullable error) {
        if (error) {
            NSString *errorDescription = [NSString stringWithFormat:@"Send failed: %@", error.localizedDescription];
            [SVProgressHUD showErrorWithStatus:errorDescription];
        } else {
            if (feedbacks.count > 0) {
                NSInteger startIndex = self.messages.count;
                [self.messages addObject:feedbacks[0]];
                NSIndexPath *path = [NSIndexPath indexPathForRow:startIndex inSection:0];
                [self.chatTableView performBatchUpdates:^{
                    [self.chatTableView insertRowsAtIndexPaths:@[path] withRowAnimation:UITableViewRowAnimationNone];
                } completion:^(BOOL finished) {
                    [self scrollToBottom];
                }];
            }
            self.sendView.sendTextField.text = @"";
            [self textfieldEditingChanged:self.sendView.sendTextField];
        }
    }];

#else

    CustomerServiceMessageModel *userMsg = [[CustomerServiceMessageModel alloc] initWithContent:userText isSend:YES];
    [self.messages addObject:userMsg];
    [CustomerServiceMessageModel saveMsgs];
    self.sendView.sendTextField.text = @"";
    [self.chatTableView reloadData];
    [self scrollToBottom];

    // 延迟 0.5 秒执行自动回复
    dispatch_time_t popTime = dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC));
    dispatch_after(popTime, dispatch_get_main_queue(), ^{
        NSString *answer = @"Okay, we have received your feedback on the issue and are currently working on it. We will inform you of the results as soon as possible. Please be patient and wait.";
        CustomerServiceMessageModel *serviceMsg = [[CustomerServiceMessageModel alloc] initWithContent:answer isSend:NO];
        [self.messages addObject:serviceMsg];
        [CustomerServiceMessageModel saveMsgs];
        [self.chatTableView reloadData];
        [self scrollToBottom];
    });

#endif

}

- (void)openPhotoLibrary {
    if (![UIImagePickerController isSourceTypeAvailable:UIImagePickerControllerSourceTypePhotoLibrary]) {
        [SVProgressHUD showErrorWithStatus:@"Unable to access photo library"];
        return;
    }
    UIImagePickerController *picker = [[UIImagePickerController alloc] init];
    picker.sourceType = UIImagePickerControllerSourceTypePhotoLibrary;
    picker.delegate = self;
    picker.modalPresentationStyle = UIModalPresentationFullScreen;
    [self presentViewController:picker animated:YES completion:nil];
}

- (void)imagePickerControllerDidCancel:(UIImagePickerController *)picker {
    [picker dismissViewControllerAnimated:YES completion:nil];
}

- (void)imagePickerController:(UIImagePickerController *)picker didFinishPickingMediaWithInfo:(NSDictionary<UIImagePickerControllerInfoKey,id> *)info {
    UIImage *image = info[UIImagePickerControllerEditedImage];
    if (!image) {
        image = info[UIImagePickerControllerOriginalImage];
    }
    NSURL *pickedImageURL = info[UIImagePickerControllerImageURL];
    if (!pickedImageURL && image) {
        pickedImageURL = [self saveImageToTempFile:image];
    }
    [picker dismissViewControllerAnimated:YES completion:nil];
    if (!image) {
        [SVProgressHUD showErrorWithStatus:@"Image selection failed"];
        return;
    }
    if (!pickedImageURL) {
        [SVProgressHUD showErrorWithStatus:@"Image read failed"];
        return;
    }
    NSData *previewData = UIImageJPEGRepresentation(image, 0.6);
    NSString *previewBase64 = previewData.length > 0 ? [previewData base64EncodedStringWithOptions:0] : @"";
    NSString *dataURI = previewBase64.length > 0 ? [NSString stringWithFormat:@"data:image/jpeg;base64,%@", previewBase64] : pickedImageURL.absoluteString;
    NSInteger localIndex = self.messages.count;
    CustomerServiceMessageModel *localModel = [CustomerServiceMessageModel new];
    localModel.isSend = YES;
    localModel.type = CustomerServiceMessageTypeImage;
    localModel.content = @"";
    localModel.imageURL = dataURI;
    localModel.imageWidth = image.size.width;
    localModel.imageHeight = image.size.height;
    NSDateFormatter *fmt = [[NSDateFormatter alloc] init];
    fmt.locale = [NSLocale localeWithLocaleIdentifier:@"en_US_POSIX"];
    NSTimeZone *tz = [NSTimeZone timeZoneWithName:@"Asia/Shanghai"];
    fmt.timeZone = tz ?: [NSTimeZone timeZoneForSecondsFromGMT:8*3600];
    fmt.dateFormat = @"yyyy-MM-dd HH:mm:ss";
    localModel.time = [fmt stringFromDate:[NSDate date]];
    localModel.msgId = (self.messages.count > 0 ? self.messages.lastObject.msgId : 0) + 1;
    [self.messages addObject:localModel];
    NSIndexPath *localPath = [NSIndexPath indexPathForRow:localIndex inSection:0];
    [self.chatTableView performBatchUpdates:^{
        [self.chatTableView insertRowsAtIndexPaths:@[localPath] withRowAnimation:UITableViewRowAnimationNone];
    } completion:^(BOOL finished) {
        [self scrollToBottom];
    }];

#if ENABLE_FEEDBACK

    [CustomerServiceManager.sharedManager sendFeedbackImage:pickedImageURL completion:^(NSArray<CustomerServiceMessageModel *> * _Nullable feedbacks, NSError * _Nullable error) {
        if (error) {
            NSString *errorDescription = [NSString stringWithFormat:@"Image send failed: %@", error.localizedDescription];
            [SVProgressHUD showErrorWithStatus:errorDescription];
            return;
        }
        if (feedbacks.count > 0) {
            if (localIndex < self.messages.count) {
                self.messages[localIndex] = feedbacks[0];
                [self.chatTableView reloadRowsAtIndexPaths:@[[NSIndexPath indexPathForRow:localIndex inSection:0]] withRowAnimation:UITableViewRowAnimationNone];
            } else {
                NSInteger startIndex = self.messages.count;
                [self.messages addObject:feedbacks[0]];
                NSIndexPath *path = [NSIndexPath indexPathForRow:startIndex inSection:0];
                [self.chatTableView performBatchUpdates:^{
                    [self.chatTableView insertRowsAtIndexPaths:@[path] withRowAnimation:UITableViewRowAnimationNone];
                } completion:^(BOOL finished) {
                    [self scrollToBottom];
                }];
            }
        } else {
            [UIView showHUDWithStatus:@"Image sent" imageName:@"Success"];
        }
    }];

#else

    [CustomerServiceMessageModel saveMsgs];

#endif

}

- (NSURL *)saveImageToTempFile:(UIImage *)image {
    if (!image) { return nil; }
    NSData *imageData = UIImageJPEGRepresentation(image, 0.8);
    if (!imageData || imageData.length == 0) { return nil; }
    NSString *fileName = [NSString stringWithFormat:@"feedback_%@.jpg", NSUUID.UUID.UUIDString];
    NSString *tempPath = [NSTemporaryDirectory() stringByAppendingPathComponent:fileName];
    NSURL *tempURL = [NSURL fileURLWithPath:tempPath];
    NSError *error = nil;
    BOOL ok = [imageData writeToURL:tempURL options:NSDataWritingAtomic error:&error];
    if (!ok || error) { return nil; }
    return tempURL;
}


#pragma mark - table view

- (void)scrollToBottom {
    [self ensureBottomVisibleWithRetries:3 animated:YES];
}

- (void)scrollToBottomAnimated:(BOOL)animated {
    if (self.messages.count > 0) {
        [self.view layoutIfNeeded];
        [self.chatTableView layoutIfNeeded];
        CGFloat contentHeight = self.chatTableView.contentSize.height;
        CGFloat tableHeight = CGRectGetHeight(self.chatTableView.bounds);
        UIEdgeInsets adjustedInsets = self.chatTableView.adjustedContentInset;
        CGFloat targetY = MAX(-adjustedInsets.top, contentHeight - tableHeight + adjustedInsets.bottom);
        CGPoint target = CGPointMake(0, targetY);
        [self.chatTableView setContentOffset:target animated:animated];
    }
}

- (BOOL)isNearBottom {
    CGFloat visibleBottom = self.chatTableView.contentOffset.y + CGRectGetHeight(self.chatTableView.bounds);
    CGFloat contentBottom = self.chatTableView.contentSize.height + self.chatTableView.adjustedContentInset.bottom;
    return (contentBottom - visibleBottom) <= ZOOM(120);
}

- (void)ensureBottomVisibleWithRetries:(NSInteger)retries animated:(BOOL)animated {
    [self scrollToBottomAnimated:animated];
    if (retries <= 0) { return; }
    __weak typeof(self) weakSelf = self;
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.06 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        __strong typeof(weakSelf) strongSelf = weakSelf;
        if (!strongSelf) { return; }
        [strongSelf ensureBottomVisibleWithRetries:retries - 1 animated:NO];
    });
}

- (void)scrollViewDidScroll:(UIScrollView *)scrollView {
    if (scrollView == self.chatTableView) {

#if ENABLE_FEEDBACK

        [self loadOlderIfNeeded];

#endif

    }
}


#pragma mark - UITableViewDataSource

- (NSInteger)tableView:(UITableView *)tableView numberOfRowsInSection:(NSInteger)section {
    return self.messages.count;
}

- (UITableViewCell *)tableView:(UITableView *)tableView cellForRowAtIndexPath:(NSIndexPath *)indexPath {
    CustomerServiceMessageCell *cell = [tableView dequeueReusableCellWithIdentifier:@"CustomerServiceMessageCell" forIndexPath:indexPath];
    CustomerServiceMessageModel *item = self.messages[indexPath.row];

#if ENABLE_FEEDBACK

    if (item.type == CustomerServiceMessageTypeImage) {
        __weak typeof(self) weakSelf = self;
        __weak typeof(cell) weakCell = cell;
        cell.onImageSizeUpdate = ^(CGSize imageSize) {
            __strong typeof(weakSelf) strongSelf = weakSelf;
            CustomerServiceMessageCell *strongCell = weakCell;
            if (!strongSelf || !strongCell) { return; }
            NSIndexPath *currentIndexPath = [strongSelf.chatTableView indexPathForCell:strongCell];
            if (!currentIndexPath || currentIndexPath.row >= strongSelf.messages.count) { return; }
            CustomerServiceMessageModel *m = strongSelf.messages[currentIndexPath.row];
            if (m) {
                if (fabs(m.imageWidth - imageSize.width) <= 0.5f && fabs(m.imageHeight - imageSize.height) <= 0.5f) {
                    return;
                }
                BOOL shouldStickToBottom = [strongSelf isNearBottom] || currentIndexPath.row == (strongSelf.messages.count - 1);
                m.imageWidth = imageSize.width;
                m.imageHeight = imageSize.height;
                [strongSelf.chatTableView beginUpdates];
                [strongSelf.chatTableView endUpdates];
                if (shouldStickToBottom) {
                    [strongSelf ensureBottomVisibleWithRetries:3 animated:NO];
                }
            }
        };
        cell.onImageTap = ^(UIImage *image) {
            __strong typeof(weakSelf) strongSelf = weakSelf;
            if (!strongSelf || !image) { return; }
            [strongSelf presentImagePreview:image];
        };
        [cell configureWithImageURL:item.imageURL imageSize:CGSizeMake(item.imageWidth, item.imageHeight) isSender:item.isSend];
    } else {
        NSString *content = item.content ?: @"";
        cell.onImageSizeUpdate = nil;
        cell.onImageTap = nil;
        [cell configureWithText:content isSender:item.isSend];
    }

#else

    if (item.type == CustomerServiceMessageTypeImage) {
        [cell configureWithImageURL:item.imageURL isSender:item.isSend];
    } else {
        UIImage *userImage = [UIImage imageNamed:@"A_user"];
        UIImage *serviceImage = [UIImage imageNamed:@"A_service"];
        [cell configureWithMessage:item iconSendImage:userImage iconReceiveImage:serviceImage];
    }

#endif

    return cell;
}


#pragma mark - UITableViewDelegate

- (CGFloat)tableView:(UITableView *)tableView heightForRowAtIndexPath:(NSIndexPath *)indexPath {
    CustomerServiceMessageModel *item = self.messages[indexPath.row];
    if (item.type == CustomerServiceMessageTypeImage) {
        CGFloat contentWidth = CGRectGetWidth(tableView.bounds);
        CGFloat maxW = contentWidth * 0.7f;
        CGFloat ratio = (item.imageHeight > 0.0f) ? (item.imageWidth / item.imageHeight) : 0.0f;
        CGFloat fixedW = (ratio > 1.0f) ? ZOOMW(220) : ZOOMW(160);
        CGFloat W = MIN(fixedW, maxW);
        CGFloat imageHeight = (ratio > 0.0f) ? (W / ratio) : ZOOM(180);
        CGFloat bubblePadding = ZOOM(6) + ZOOM(6);
        CGFloat cellMargins = ZOOM(8) + ZOOM(8);
        return imageHeight + bubblePadding + cellMargins;
    } else {
        NSString *text = item.content ?: @"";
        if (text.length == 0) {
            return ZOOM(8 + 8 + 10 + 10) + ZOOM(18);
        }
        CGFloat contentWidth = CGRectGetWidth(tableView.bounds);
        CGFloat maxBubbleWidth = contentWidth * 0.72f;
        CGFloat labelHorizontalPadding = ZOOM(12) + ZOOM(12);
        CGFloat labelVerticalPadding = ZOOM(10) + ZOOM(10);
        CGFloat cellVerticalMargins = ZOOM(8) + ZOOM(8);
        CGFloat labelWidth = MAX(0.0, maxBubbleWidth - labelHorizontalPadding);
        CGRect bounding = [text boundingRectWithSize:CGSizeMake(labelWidth, CGFLOAT_MAX)
                                             options:(NSStringDrawingUsesLineFragmentOrigin | NSStringDrawingUsesFontLeading)
                                          attributes:@{ NSFontAttributeName: [UIFont systemFontOfSize:ZOOM(16)] }
                                             context:nil];
        CGFloat labelHeight = ceil(bounding.size.height);
        CGFloat cellHeight = labelHeight + labelVerticalPadding + cellVerticalMargins;
        CGFloat minHeight = ZOOM(44);
        return MAX(cellHeight, minHeight);
    }
}


#pragma mark - Keyboard Handling

- (BOOL)textFieldShouldReturn:(UITextField *)textField {
    if (textField == self.sendView.sendTextField) {
        [textField resignFirstResponder];
    }
    return YES;
}

- (BOOL)textField:(UITextField *)textField shouldChangeCharactersInRange:(NSRange)range replacementString:(NSString *)string {
    if (textField == self.sendView.sendTextField) {
        NSString *newText = [textField.text stringByReplacingCharactersInRange:range withString:string];
        NSString *trimmed = [newText stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
        BOOL hasText = trimmed.length > 0;
        self.sendView.sendButton.enabled = hasText;
        self.sendView.sendButton.alpha = hasText ? 1.0 : 0.6;
    }
    return YES;
}

- (void)keyboardWillShow:(NSNotification *)notification {
    NSDictionary *userInfo = notification.userInfo ?: @{};
    CGRect keyboardEndFrameInWindow = [userInfo[UIKeyboardFrameEndUserInfoKey] CGRectValue];
    CGRect keyboardEndFrame = [self.view convertRect:keyboardEndFrameInWindow fromView:nil];
    CGFloat overlap = MAX(0.0, CGRectGetMaxY(self.view.bounds) - CGRectGetMinY(keyboardEndFrame));
    if (@available(iOS 11.0, *)) {
        overlap = MAX(0.0, overlap - self.view.safeAreaInsets.bottom);
    }
    NSTimeInterval duration = [userInfo[UIKeyboardAnimationDurationUserInfoKey] doubleValue];
    UIViewAnimationOptions options = ((UIViewAnimationOptions)[userInfo[UIKeyboardAnimationCurveUserInfoKey] integerValue] << 16);
    [_sendView mas_updateConstraints:^(MASConstraintMaker *make) {
        make.bottom.equalTo(self.view).offset(-overlap - 10);
    }];
    [UIView animateWithDuration:duration delay:0 options:options animations:^{
        [self.view layoutIfNeeded];
        [self scrollToBottomAnimated:NO];
    } completion:nil];
}

- (void)keyboardWillHide:(NSNotification *)notification {
    NSDictionary *userInfo = notification.userInfo ?: @{};
    NSTimeInterval duration = [userInfo[UIKeyboardAnimationDurationUserInfoKey] doubleValue];
    UIViewAnimationOptions options = ((UIViewAnimationOptions)[userInfo[UIKeyboardAnimationCurveUserInfoKey] integerValue] << 16);
    [_sendView mas_updateConstraints:^(MASConstraintMaker *make) {
        make.bottom.equalTo(self.view);
    }];
    [UIView animateWithDuration:duration delay:0 options:options animations:^{
        [self.view layoutIfNeeded];
    } completion:nil];
}


#pragma mark - UIGestureRecognizerDelegate

- (BOOL)gestureRecognizer:(UIGestureRecognizer *)gestureRecognizer shouldReceiveTouch:(UITouch *)touch {
    if ([touch.view isKindOfClass:[UIControl class]]) {
        return NO;
    }
