#pragma mark - Private Helpers

/**
 安全取值：将 nil/NSNull 视为 nil
 */
 - (id)safeValueForKey:(NSString *)key fromDictionary:(NSDictionary *)dict {
    id value = [dict objectForKey:key];
    if (value == [NSNull null] || value == nil) {
        return nil;
    }
    return value;
}

/**
 统一处理反馈接口的原始 JSON
 - 校验响应结构与状态码
 - 失败返回中文错误
- 成功映射为 CustomerServiceMessageModel 数组
 */
- (void)processFeedbackJSON:(id)json error:(NSError *)error completion:(WBCustomerServiceListCallback)completion {
    if (error) {
        if (completion) {
            NSError *cnError = [NSError errorWithDomain:@"CustomerServiceManager" code:error.code userInfo:@{NSLocalizedDescriptionKey: [NSString stringWithFormat:@"Request error: %@", error.localizedDescription ?: @"Unknown error"]}];
            completion(nil, cnError);
        }
        return;
    }
    if (!json || json == [NSNull null] || ![json isKindOfClass:[NSDictionary class]]) {
        if (completion) {
            NSError *respErr = [NSError errorWithDomain:@"CustomerServiceManager" code:-1 userInfo:@{NSLocalizedDescriptionKey: @"Invalid response data"}];
            completion(nil, respErr);
        }
        return;
    }
    NSDictionary *dict = (NSDictionary *)json;
    NSNumber *code = dict[@"code"];
    NSString *message = dict[@"message"];
    if ((code && [code integerValue] == 200 && [message isKindOfClass:NSString.class] && [message isEqualToString:@"success"])) {
        NSDictionary *data = [self safeValueForKey:@"data" fromDictionary:dict];
        NSArray<CustomerServiceMessageModel *> *result = [self mapFeedbackListFromData:data];
        if (completion) {
            completion(result ?: @[], nil);
        }
    } else {
        if (completion) {
            NSInteger ec = [code isKindOfClass:NSNumber.class] ? [code integerValue] : -2;
            NSString *desc = ([message isKindOfClass:NSString.class] && [(NSString *)message length] > 0) ? [NSString stringWithFormat:@"Request failed: %@", (NSString *)message] : @"Request failed";
            NSError *respErr = [NSError errorWithDomain:@"CustomerServiceManager" code:ec userInfo:@{NSLocalizedDescriptionKey: desc}];
            completion(nil, respErr);
        }
    }
}

/**
 将 data.list 映射为 CustomerServiceMessageModel 数组
 */
- (NSArray<CustomerServiceMessageModel *> *)mapFeedbackListFromData:(NSDictionary *)data {
    id listRaw = [self safeValueForKey:@"list" fromDictionary:data];
    NSArray *list = [listRaw isKindOfClass:NSArray.class] ? (NSArray *)listRaw : nil;
    NSMutableArray<CustomerServiceMessageModel *> *result = [NSMutableArray arrayWithCapacity:list.count];
    if (list) {
        for (id item in list) {
            NSDictionary *m = [item isKindOfClass:NSDictionary.class] ? (NSDictionary *)item : nil;
            if (!m) { continue; }
            CustomerServiceMessageModel *model = [self modelFromDict:m];
            if (model) {
                [result addObject:model];
            }
        }
    }
    return result;
}

/**
 单条反馈字典 -> CustomerServiceMessageModel
 - 兼容类型：id/admin 支持 NSString/NSNumber
 - 时间：保留后端字符串 created_at
