- (void)onSendMessageButtonTapped:(NSNotification *)notification {
    // 获取输入框中的消息内容
    NSString *messageText ;
    if(notification.object){
        messageText=notification.object;
    }
    else{
        // 获取输入框中的消息内容
        messageText = _messageView.inputMessageField.text;
    }

    // 检测是否为空消息，纯空格或者纯换行符
    NSString *trimmedString = [messageText stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    if ([messageText isEqualToString:@""]||[trimmedString length] == 0) {
        // 如果消息为空，则不处理
        return;
    }
    // 所发消息需要的显示高度
    CGFloat cellHeight = [self getStringWidthToCellHeight:messageText];
    // 创建新的发送消息对象，这里context从上一条MessageTypeReceived属性的MessageModel中或许
    [self.messages addObject:[[MessageModel alloc] initWithText:messageText time:[NSDate date] type:MessageTypeSent accountId:self.aiID cellHeight:cellHeight context:@"" Done:NO]];
    [self.messages addObject:[[MessageModel alloc] initWithText:@"思考中..." time:[NSDate date] type:MessageTypeReceived accountId:self.aiID cellHeight:[self getStringWidthToCellHeight:@"思考中..."] context:self.messages[self.messages.count-2].context Done:NO]];
    // 清空输入框
    _messageView.inputMessageField.text = @"";
    [self.chatTableView reloadData];    // 刷新表格视图以显示新的消息
    [self scrollToBottom];  // 滚动到最下方最新消息
    [MessageModel saveMessagesForAccount:self.aiID];    // 保存消息
    self.messageView.inputMessageField.enabled = NO;
    self.messageView.sendButton.enabled = NO;  // 按钮不可点击
    self.messageView.sendButton.alpha = 0.5;  // 透明度也可以稍微降低表示不可点击状态
    [self sendPOSTRequestAndHandleStreamResponse:messageText];  // 发送消息，接收ai应答信息
}
#pragma mark - 网络请求
/*
 使用NSURLSessionDataDelegate和didReceiveData而非completionHandler
 底层差异：
 数据流和缓冲机制的差异：
 NSURLSessionDataDelegate：基于 数据流，数据分批传输到应用层，系统只负责接收，处理逻辑由开发者决定。每个数据块到达时，didReceiveData: 方法被调用，允许你立即处理数据。
 completionHandler：基于 缓冲机制，系统负责将所有数据接收完毕并缓存在本地，只有当全部数据接收完毕后才调用 completionHandler，并将数据一次性提供给应用层。
 触发时机的差异：
 NSURLSessionDataDelegate：代理方法根据网络传输状态多次触发。每当数据从网络到达时，系统会调用代理方法，开发者可以在这些调用中实时处理数据。
 completionHandler：只有在数据完全接收后，才会一次性触发。你无法在数据传输过程中干预或处理部分数据。
 */
// 发送POST请求并处理流响应
- (void)sendPOSTRequestAndHandleStreamResponse:(NSString *)messageText {
    // 配置 URL 和请求
    NSURL *url = [NSURL URLWithString:@"https://xportal.sposervice.com/ai"];
    NSMutableURLRequest *request = [NSMutableURLRequest requestWithURL:url];
    request.HTTPMethod = @"POST";
    [request setValue:@"application/json" forHTTPHeaderField:@"Content-Type"];
    // 每次开始新对话时要初始化如下内容
    _nowString=nil;
    // 注意：这里accumulatedResponse和buffer和是一个可变字符串，不要赋空，而要赋为空串
    [self.buffer setString:@""];
    [self.accumulatedResponse setString:@""];
    NSDictionary *params;
    if(self.messages.lastObject.context==nil){
        self.context=@[];
    }
    else{
        NSData *jsonData = [self.messages.lastObject.context dataUsingEncoding:NSUTF8StringEncoding];
        NSError *error;
        self.context = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:&error];
        if (error) {
            NSLog(@"Error parsing JSON: %@", error.localizedDescription);
            self.context=@[];
        }
    }
    if(self.Identity == nil){
        params = @{@"model": @"gemma2:2b",
                   @"prompt": messageText,
                   @"context": self.context
        };
    }
    else{
        params = @{@"model": @"gemma2:2b",
                   @"prompt": messageText,
                   @"context": self.context,
                   @"system":self.Identity
        };
    }
    NSData *postData = [NSJSONSerialization dataWithJSONObject:params options:0 error:nil];
    request.HTTPBody = postData;
    // 创建一个会话配置
    NSURLSessionConfiguration *sessionConfig = [NSURLSessionConfiguration defaultSessionConfiguration];
    // 创建 NSURLSession，并设置 delegate 和 delegateQueue
    NSURLSession *session = [NSURLSession sessionWithConfiguration:sessionConfig delegate:self delegateQueue:nil];
    self.dataTask = [session dataTaskWithRequest:request];
    [self.dataTask resume];
}
// 实现 NSURLSessionDataDelegate
// 注意：context数组的长度与ai返回的内容的长度成正比，如果ai返回一篇长文本会导致最后一条消息中的context太长，消息被切断，需要进行拼接
// 注意：会出现几条消息粘连在一起的情况，用换行符进行切割
// 注意：暂不确定以上两种情况会不会同时出现
- (void)URLSession:(NSURLSession *)session dataTask:(NSURLSessionDataTask *)dataTask didReceiveData:(NSData *)data {
    // 将接收到的数据转换为字符串，以便于处理
    NSString *dataString = [[NSString alloc] initWithData:data encoding:NSUTF8StringEncoding];
    NSError *error = nil;
    NSString *jsonPart;
    //进行切割工作
    NSRegularExpression *regex = [NSRegularExpression regularExpressionWithPattern:@"\\n\\n|\\n" options:0 error:&error];
    NSString *modifiedString = [regex stringByReplacingMatchesInString:dataString options:0 range:NSMakeRange(0, dataString.length) withTemplate:@"|"];
    NSArray *jsonStrings = [modifiedString componentsSeparatedByString:@"|"];
    for (NSString *DataString in jsonStrings) {
        // 处理每个 JSON 字符串
        if ([DataString hasPrefix:@"data:"]) {
            jsonPart = [DataString substringFromIndex:5];
            if(![jsonPart isEqualToString:@""]){
                [self processJSONMessage:jsonPart];
            }
        }else{
            if(![DataString isEqualToString:@""]){
                [self processJSONMessage:DataString];
            }
        }
    }
}
//进行拼接工作
static const unichar closingBrace = '}';
- (void)processJSONMessage:(NSString *)jsonString {
    // 将字符串转换为 NSData 以进行 JSON 解析
    NSData *jsonData = [jsonString dataUsingEncoding:NSUTF8StringEncoding];
    NSError *jsonError;
    NSDictionary *responseDict = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:&jsonError];
    if (jsonError) {
        NSLog(@"Failed to parse JSON from server response: %@", jsonError);
        //不确定是否是因为消息被切断而导致的json解析出错，所以需要进行拼接
        [self.buffer appendString:jsonString];
        // 检测最后一个字符，如果是'}'，则代表是消息被切断导致的，json解析最后一条消息
        if([self.buffer characterAtIndex:self.buffer.length - 1]==closingBrace){
            NSLog(@"已拼接最后一条消息");
            // 注意：复用jsonError时要赋空
            jsonError = nil;
            jsonData = [self.buffer dataUsingEncoding:NSUTF8StringEncoding];
            responseDict = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:&jsonError];
            if(jsonError){
                NSLog(@"Failed to parse JSON from server response: %@", jsonError);
                NSLog(@"接收到的服务器消息: %@", self.buffer);
                return;
            }
            BOOL done = [responseDict[@"done"] boolValue];
            if(done){
                [self processDoneMessage:responseDict];
            }
        }
        return; // 跳过解析失败的消息
    }
    _preString = _nowString;
    _nowString = responseDict[@"response"];
    BOOL done = [responseDict[@"done"] boolValue];
    if (done) {
        [self processDoneMessage:responseDict];
    }
    if (_preString) {
        _preString = [_preString stringByReplacingOccurrencesOfString:@"*" withString:@""];
        _preString = [_preString stringByReplacingOccurrencesOfString:@"\n\n+" withString:@"\n" options:NSRegularExpressionSearch range:NSMakeRange(0, _preString.length)];
        [self.accumulatedResponse appendString:_preString];
        // 更新最后一条消息
        MessageModel *lastMessage = [self.messages lastObject];
        lastMessage.text = self.accumulatedResponse;
        lastMessage.cellHeight = [self getStringWidthToCellHeight:self.accumulatedResponse];
        dispatch_async(dispatch_get_main_queue(), ^{
            [self.chatTableView reloadData];
            [self scrollToBottom];
        });
    }
}
- (void)processDoneMessage:(NSDictionary *)Dict{
    dispatch_async(dispatch_get_main_queue(), ^{
        // 提取 context
        NSArray *lastContext = self.context;
        NSArray *ReContext = Dict[@"context"];
        // 确保不超出 bounds
        NSRange range;
        NSArray *contextArray;
        // 确保不超出 bounds
        if (ReContext.count == 1||lastContext.count < ReContext.count) {  //服务器哪里有一个特殊消息，里面的context=[1];
            // 当 ReContext.count 为 1 时，直接将 contextArray 设为 lastContext
            contextArray = lastContext;
        } else {
            range = NSMakeRange(lastContext.count, ReContext.count - lastContext.count);
            contextArray = [ReContext subarrayWithRange:range];
        }
        NSError *error;
        NSData *jsonData = [NSJSONSerialization dataWithJSONObject:contextArray options:0 error:&error];
        if (!error) {
            self.messages.lastObject.context = [[NSString alloc] initWithData:jsonData encoding:NSUTF8StringEncoding];
            NSLog(@"Converted string: %@", self.messages.lastObject.context);
        } else {
            NSLog(@"Error converting array to JSON string: %@", error.localizedDescription);
        }
        self.messages.lastObject.done = YES;
        self.messages[self.messages.count-2].done=YES;
        self.messages[self.messages.count-3].context=@"";
        [MessageModel saveMessagesForAccount:self.aiID]; // 保存消息
        self.messageView.inputMessageField.enabled = YES;
        self.messageView.sendButton.enabled = YES; // 按钮恢复可点击
        self.messageView.sendButton.alpha = 1.0; // 恢复透明度
        //[self.editView modifyTipWords:self.messages.lastObject.text]; // 修改最新聊天信息
        // 打印文件内容以验证
//        NSString *filePath = [MessageModel filePathForAccount:self.aiID];
//        NSData *data = [NSData dataWithContentsOfFile:filePath];
//        NSString *fileContent = [[NSString alloc] initWithData:data encoding:NSUTF8StringEncoding];
//        NSLog(@"文件内容: %@", fileContent);
    });
    NSLog(@"响应结束");
    return;
}
