+//
+//  WhatsAppViewController.m
+//  Nook
+//
+//  Created by 蒙俊竹 on 2026/3/16.
+//
+
+#import "WhatsAppViewController.h"
+#import "PrefixHeader.h"
+
+static NSString * const kNookAIChatListFileName = @"nook_ai_chat_list.json";
+
+@interface NookChatConversationViewController : UIViewController <UITableViewDelegate, UITableViewDataSource, UITextFieldDelegate>
+
+- (instancetype)initWithChatId:(NSString *)chatId title:(NSString *)title;
+
+@end
+
+@interface WhatsAppViewController () <UITableViewDelegate, UITableViewDataSource>
+
+@property (nonatomic, strong) UITableView *tableView;
+@property (nonatomic, strong) NSMutableArray<NSMutableDictionary *> *chatItems;
+
+@end
+
+@implementation WhatsAppViewController
+
+- (void)viewDidLoad {
+    [super viewDidLoad];
+    self.title = @"AI聊天列表";
+    self.view.backgroundColor = BACKGROUND_COLOR;
+    self.navigationItem.rightBarButtonItem = [[UIBarButtonItem alloc] initWithBarButtonSystemItem:UIBarButtonSystemItemAdd target:self action:@selector(addConversation)];
+
+    [self.view addSubview:self.tableView];
+    [self.tableView mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.edges.equalTo(self.view);
+    }];
+
+    [self loadChatItems];
+}
+
+#pragma mark - Data
+
+- (NSString *)documentsPath {
+    NSArray<NSString *> *paths = NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES);
+    return paths.firstObject ?: NSTemporaryDirectory();
+}
+
+- (NSString *)chatListPath {
+    return [[self documentsPath] stringByAppendingPathComponent:kNookAIChatListFileName];
+}
+
+- (NSArray<NSDictionary *> *)defaultChats {
+    return @[
+        @{@"id": @"emotion", @"title": @"情感助手", @"subtitle": @"可以和我聊情绪和关系问题"},
+        @{@"id": @"sport", @"title": @"运动搭子", @"subtitle": @"今天想练什么，我帮你安排"},
+        @{@"id": @"music", @"title": @"音乐推荐", @"subtitle": @"按你心情挑歌单"},
+        @{@"id": @"learn", @"title": @"学习教练", @"subtitle": @"把目标拆成每天可执行步骤"}
+    ];
+}
+
+- (void)loadChatItems {
+    NSData *data = [NSData dataWithContentsOfFile:[self chatListPath]];
+    NSArray *json = nil;
+    if (data.length > 0) {
+        id obj = [NSJSONSerialization JSONObjectWithData:data options:0 error:nil];
+        if ([obj isKindOfClass:[NSArray class]]) {
+            json = (NSArray *)obj;
+        }
+    }
+
+    NSMutableArray<NSMutableDictionary *> *result = [NSMutableArray array];
+    for (NSDictionary *item in json.count > 0 ? json : [self defaultChats]) {
+        if (![item isKindOfClass:[NSDictionary class]]) { continue; }
+        NSString *chatId = [item[@"id"] isKindOfClass:[NSString class]] ? item[@"id"] : NSUUID.UUID.UUIDString;
+        NSString *title = [item[@"title"] isKindOfClass:[NSString class]] ? item[@"title"] : @"新会话";
+        NSString *subtitle = [item[@"subtitle"] isKindOfClass:[NSString class]] ? item[@"subtitle"] : @"点击进入会话";
+        [result addObject:[@{@"id": chatId, @"title": title, @"subtitle": subtitle} mutableCopy]];
+    }
+
+    self.chatItems = result;
+    [self saveChatItems];
+    [self.tableView reloadData];
+}
+
+- (void)saveChatItems {
+    NSMutableArray *arr = [NSMutableArray arrayWithCapacity:self.chatItems.count];
+    for (NSDictionary *item in self.chatItems) {
+        [arr addObject:@{
+            @"id": item[@"id"] ?: @"",
+            @"title": item[@"title"] ?: @"",
+            @"subtitle": item[@"subtitle"] ?: @""
+        }];
+    }
+    NSData *data = [NSJSONSerialization dataWithJSONObject:arr options:0 error:nil];
+    if (data.length > 0) {
+        [data writeToFile:[self chatListPath] atomically:YES];
+    }
+}
+
+#pragma mark - Events
+
+- (void)addConversation {
+    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"新建会话" message:nil preferredStyle:UIAlertControllerStyleAlert];
+    [alert addTextFieldWithConfigurationHandler:^(UITextField * _Nonnull textField) {
+        textField.placeholder = @"输入会话名称";
+    }];
+    __weak typeof(self) weakSelf = self;
+    [alert addAction:[UIAlertAction actionWithTitle:@"取消" style:UIAlertActionStyleCancel handler:nil]];
+    [alert addAction:[UIAlertAction actionWithTitle:@"创建" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
+        __strong typeof(weakSelf) self = weakSelf;
+        if (!self) { return; }
+        UITextField *input = alert.textFields.firstObject;
+        NSString *title = [[input.text ?: @"" stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]] copy];
+        if (title.length == 0) {
+            title = @"新会话";
+        }
+        NSMutableDictionary *newItem = [@{
+            @"id": NSUUID.UUID.UUIDString,
+            @"title": title,
+            @"subtitle": @"点击进入会话"
+        } mutableCopy];
+        [self.chatItems insertObject:newItem atIndex:0];
+        [self saveChatItems];
+        [self.tableView reloadData];
+    }]];
+    [self presentViewController:alert animated:YES completion:nil];
+}
+
+- (void)openConversationAtIndex:(NSInteger)index {
+    if (index < 0 || index >= self.chatItems.count) { return; }
+    NSDictionary *item = self.chatItems[index];
+    NookChatConversationViewController *vc = [[NookChatConversationViewController alloc] initWithChatId:item[@"id"] title:item[@"title"]];
+    vc.hidesBottomBarWhenPushed = YES;
+    [self.navigationController pushViewController:vc animated:YES];
+}
+
+#pragma mark - UITableViewDataSource
+
+- (NSInteger)tableView:(UITableView *)tableView numberOfRowsInSection:(NSInteger)section {
+    return self.chatItems.count;
+}
+
+- (UITableViewCell *)tableView:(UITableView *)tableView cellForRowAtIndexPath:(NSIndexPath *)indexPath {
+    UITableViewCell *cell = [tableView dequeueReusableCellWithIdentifier:@"NookAIChatCell" forIndexPath:indexPath];
+    NSDictionary *item = self.chatItems[indexPath.row];
+    cell.textLabel.text = item[@"title"];
+    cell.detailTextLabel.text = item[@"subtitle"];
+    cell.accessoryType = UITableViewCellAccessoryDisclosureIndicator;
+    cell.backgroundColor = WHITE_COLOR;
+    return cell;
+}
+
+- (void)tableView:(UITableView *)tableView didSelectRowAtIndexPath:(NSIndexPath *)indexPath {
+    [tableView deselectRowAtIndexPath:indexPath animated:YES];
+    [self openConversationAtIndex:indexPath.row];
+}
+
+#pragma mark - UITableViewDelegate
+
+- (CGFloat)tableView:(UITableView *)tableView heightForRowAtIndexPath:(NSIndexPath *)indexPath {
+    return ZOOM(78);
+}
+
+#pragma mark - Lazy
+
+- (UITableView *)tableView {
+    if (!_tableView) {
+        _tableView = [[UITableView alloc] initWithFrame:CGRectZero style:UITableViewStyleInsetGrouped];
+        [_tableView registerClass:[UITableViewCell class] forCellReuseIdentifier:@"NookAIChatCell"];
+        _tableView.delegate = self;
+        _tableView.dataSource = self;
+        _tableView.rowHeight = ZOOM(78);
+        _tableView.estimatedRowHeight = ZOOM(78);
+        _tableView.separatorStyle = UITableViewCellSeparatorStyleSingleLine;
+    }
+    return _tableView;
+}
+
+@end
+
+@interface NookChatConversationViewController ()
+
+@property (nonatomic, copy) NSString *chatId;
+@property (nonatomic, strong) UITableView *tableView;
+@property (nonatomic, strong) UIView *inputContainer;
+@property (nonatomic, strong) UITextField *inputField;
+@property (nonatomic, strong) UIButton *sendButton;
+@property (nonatomic, strong) NSMutableArray<NSMutableDictionary *> *messages;
+@property (nonatomic, strong) MASConstraint *bottomConstraint;
+
+@end
+
+@implementation NookChatConversationViewController
+
+- (instancetype)initWithChatId:(NSString *)chatId title:(NSString *)title {
+    self = [super init];
+    if (self) {
+        _chatId = [chatId copy];
+        self.title = title.length > 0 ? title : @"会话";
+    }
+    return self;
+}
+
+- (void)viewDidLoad {
+    [super viewDidLoad];
+    self.view.backgroundColor = BACKGROUND_COLOR;
+
+    [self.view addSubview:self.tableView];
+    [self.view addSubview:self.inputContainer];
+    [self.inputContainer addSubview:self.inputField];
+    [self.inputContainer addSubview:self.sendButton];
+
+    [self.inputContainer mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.left.right.equalTo(self.view);
+        self.bottomConstraint = make.bottom.equalTo(self.view);
+        make.height.mas_equalTo(ZOOM(70));
+    }];
+    [self.sendButton mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.right.equalTo(self.inputContainer).offset(ZOOM(-16));
+        make.centerY.equalTo(self.inputContainer);
+        make.width.mas_equalTo(ZOOM(68));
+        make.height.mas_equalTo(ZOOM(40));
+    }];
+    [self.inputField mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.left.equalTo(self.inputContainer).offset(ZOOM(16));
+        make.right.equalTo(self.sendButton.mas_left).offset(ZOOM(-10));
+        make.centerY.equalTo(self.inputContainer);
+        make.height.mas_equalTo(ZOOM(40));
+    }];
+    [self.tableView mas_makeConstraints:^(MASConstraintMaker *make) {
+        make.top.left.right.equalTo(self.view);
+        make.bottom.equalTo(self.inputContainer.mas_top);
+    }];
+
+    [self loadMessages];
+    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillChange:) name:UIKeyboardWillChangeFrameNotification object:nil];
+}
+
+- (void)dealloc {
+    [[NSNotificationCenter defaultCenter] removeObserver:self];
+}
+
+#pragma mark - Data
+
+- (NSString *)messagesPath {
+    NSArray<NSString *> *paths = NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES);
+    NSString *doc = paths.firstObject ?: NSTemporaryDirectory();
+    return [doc stringByAppendingPathComponent:[NSString stringWithFormat:@"nook_ai_chat_%@.json", self.chatId ?: @"default"]];
+}
+
+- (void)loadMessages {
+    NSData *data = [NSData dataWithContentsOfFile:[self messagesPath]];
+    NSArray *json = nil;
+    if (data.length > 0) {
+        id obj = [NSJSONSerialization JSONObjectWithData:data options:0 error:nil];
+        if ([obj isKindOfClass:[NSArray class]]) {
+            json = (NSArray *)obj;
+        }
+    }
+    self.messages = [NSMutableArray array];
+    for (NSDictionary *item in json) {
+        if (![item isKindOfClass:[NSDictionary class]]) { continue; }
+        [self.messages addObject:[item mutableCopy]];
+    }
+    if (self.messages.count == 0) {
+        [self.messages addObject:[@{@"sender": @"ai", @"text": @"你好，我在。你想先聊什么？"} mutableCopy]];
+    }
+    [self saveMessages];
+    [self.tableView reloadData];
+    [self scrollToBottomAnimated:NO];
+}
+
+- (void)saveMessages {
+    NSData *data = [NSJSONSerialization dataWithJSONObject:self.messages ?: @[] options:0 error:nil];
+    if (data.length > 0) {
+        [data writeToFile:[self messagesPath] atomically:YES];
+    }
+}
+
+#pragma mark - Events
+
+- (void)sendMessage {
+    NSString *text = [[self.inputField.text ?: @"" stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]] copy];
+    if (text.length == 0) { return; }
+
+    [self appendMessage:text sender:@"user"];
+    self.inputField.text = @"";
+    self.sendButton.enabled = NO;
+    self.sendButton.alpha = 0.6;
+
+    __weak typeof(self) weakSelf = self;
+    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.45 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
+        __strong typeof(weakSelf) self = weakSelf;
+        if (!self) { return; }
+        [self appendMessage:[self aiReplyForPrompt:text] sender:@"ai"];
+    });
+}
+
+- (void)inputChanged:(UITextField *)textField {
+    NSString *text = [[textField.text ?: @"" stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]] copy];
+    BOOL canSend = text.length > 0;
+    self.sendButton.enabled = canSend;
+    self.sendButton.alpha = canSend ? 1.0 : 0.6;
+}
+
+- (NSString *)aiReplyForPrompt:(NSString *)prompt {
+    if ([prompt containsString:@"睡"] || [prompt containsString:@"失眠"]) {
+        return @"先做一轮 4-7-8 呼吸，吸气4秒，屏息7秒，呼气8秒，做 4 轮。做完再告诉我你现在的感觉。";
+    }
+    if ([prompt containsString:@"学习"] || [prompt containsString:@"计划"]) {
+        return @"你可以先给我一个目标和截止时间，我帮你拆成每天可执行的小任务。";
+    }
+    return @"我收到了。你可以继续补充细节，我会根据你给的信息给更具体的建议。";
+}
+
+- (void)appendMessage:(NSString *)text sender:(NSString *)sender {
+    [self.messages addObject:[@{@"sender": sender ?: @"ai", @"text": text ?: @""} mutableCopy]];
+    [self saveMessages];
+    [self.tableView reloadData];
+    [self scrollToBottomAnimated:YES];
+}
+
+- (void)scrollToBottomAnimated:(BOOL)animated {
+    if (self.messages.count == 0) { return; }
