- (void)addChat {
    AIChatListAddViewController *addVC = [[AIChatListAddViewController alloc] init];

    __weak typeof(self) weakSelf = self;

    addVC.onConfirm = ^(NSString *title, UIImage *_Nullable avatarImage) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;

        AIChatListItemModel *item = [[AIChatListItemModel alloc] init];
        item.chatId = [[NSUUID UUID] UUIDString];
        item.title = title.length ? title : @"Good Friend";
        item.subtitle = @"Are you going to watch a movie after work tonight?";

        NSDateFormatter *fmt = [[NSDateFormatter alloc] init];
        fmt.dateFormat = @"HH:mm";
        item.time = [fmt stringFromDate:[NSDate date]];

        if (avatarImage) {
            NSString *abs = [AIChatListStorage avatarPathForChatId:item.chatId];
            NSData *png = UIImagePNGRepresentation(avatarImage);
            [png writeToFile:abs atomically:YES];
            item.avatarPath = [NSString stringWithFormat:@"ai_chat_list_avatars/%@.png", item.chatId];
        } else {
            item.icon = @"A_defaultAvatar";
        }

//        [self.chatItems insertObject:item atIndex:4];
        [self.chatItems addObject:item];
        [AIChatListStorage saveChatList:self.chatItems];

        [self.collectionView reloadData];
        [self dismissViewControllerAnimated:YES completion:nil];
    };

    UINavigationController *nav = [[UINavigationController alloc] initWithRootViewController:addVC];
    nav.modalPresentationStyle = UIModalPresentationFullScreen;
    [self presentViewController:nav animated:YES completion:nil];
}


