            if ((uc >= 0x1F600 && uc <= 0x1F64F) ||
                (uc >= 0x1F300 && uc <= 0x1F5FF) ||
                (uc >= 0x1F680 && uc <= 0x1F6FF) ||
                (uc >= 0x1F900 && uc <= 0x1F9FF) ||
                (uc >= 0x1FA70 && uc <= 0x1FAFF) ||
                (uc >= 0x1F1E6 && uc <= 0x1F1FF)) {
                return YES;
            }
        }
        return NO;
    } else {
        if (substring.length > 1) {
            unichar ls = [substring characterAtIndex:1];
            if (ls == 0x20E3) { // keycap
                return YES;
            }
        }
        if (hs == 0x200D || // ZWJ
            hs == 0xFE0F || // Variation Selector-16
            (hs >= 0x2600 && hs <= 0x26FF) ||
            (hs >= 0x2700 && hs <= 0x27BF)) {
            return YES;
        }
    }
    return NO;
}

- (NSString *)stringByRemovingEmojis:(NSString *)string {
    if (string.length == 0) return string ?: @"";
    NSMutableString *result = [NSMutableString string];
    [string enumerateSubstringsInRange:NSMakeRange(0, string.length)
                               options:NSStringEnumerationByComposedCharacterSequences
                            usingBlock:^(NSString * _Nullable substring, NSRange substringRange, NSRange enclosingRange, BOOL * _Nonnull stop) {
        if (substring && ![self isEmojiSubstring:substring]) {
            [result appendString:substring];
        }
    }];
    return [result copy];
}
- (void)processJSONMessage:(NSString *)jsonString {
    // 将字符串转换为 NSData 以进行 JSON 解析
    NSData *jsonData = [jsonString dataUsingEncoding:NSUTF8StringEncoding];
    NSError *jsonError;
    NSDictionary *responseDict = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:&jsonError];
    if (jsonError) {
        NSLog(@"Failed to parse JSON from server response: %@", jsonError);
        //不确定是否是因为消息被切断而导致的json解析出错，所以需要进行拼接
        [self.buffer appendString:jsonString];
        // 检测最后一个字符，如果是'}'，则代表是消息被切断导致的，json解析最后一条消息
        if ([self.buffer characterAtIndex:self.buffer.length - 1] == closingBrace) {
            NSLog(@"已拼接最后一条消息");
            // 注意：复用jsonError时要赋空
            jsonError = nil;
            jsonData = [self.buffer dataUsingEncoding:NSUTF8StringEncoding];
            responseDict = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:&jsonError];
            if (jsonError) {
                NSLog(@"Failed to parse JSON from server response: %@", jsonError);
                NSLog(@"接收到的服务器消息: %@", self.buffer);
                return;
            }
            BOOL done = [responseDict[@"done"] boolValue];
            if (done) {
                [self processDoneMessage:responseDict];
            }
        }
        return; // 跳过解析失败的消息
    }
    _preString = _nowString;
    _nowString = responseDict[@"response"];
    // 过滤 emoji
    _nowString = [self stringByRemovingEmojis:_nowString ?: @""];
    BOOL done = [responseDict[@"done"] boolValue];
    if (done) {
        [self processDoneMessage:responseDict];
        return;
    }
    if (_preString) {
        _preString = [_preString stringByReplacingOccurrencesOfString:@"*" withString:@""];
        _preString = [_preString stringByReplacingOccurrencesOfString:@"\n\n+" withString:@"\n" options:NSRegularExpressionSearch range:NSMakeRange(0, _preString.length)];
        [self.accumulatedResponse appendString:_preString];
        // 更新 Main 的最后一条（AI 占位）消息内容
        AIChatListMessageModel *lastMessage = [self.belongMessages lastObject];
        lastMessage.text = [self stringByRemovingEmojis:[self.accumulatedResponse copy]];
        dispatch_async(dispatch_get_main_queue(), ^{
            if (self.onPartialUpdate) {
                self.onPartialUpdate(lastMessage.text);
            }
        });

    }
}

- (void)processDoneMessage:(NSDictionary *)Dict {
    dispatch_async(dispatch_get_main_queue(), ^{
        NSArray *lastContext = self.context;
        NSArray *ReContext = Dict[@"context"];
        NSRange range;
        NSArray *contextArray;
        // 确保不超出 bounds
        if (ReContext.count == 1) {  //服务器那里有一个特殊消息，里面的context=[1];
            // 当 ReContext.count 为 1 时，直接将 contextArray 设为 lastContext
            contextArray = lastContext;
        } else {
            range = NSMakeRange(lastContext.count, ReContext.count - lastContext.count);
            contextArray = [ReContext subarrayWithRange:range];
        }
        NSError *error;
        NSData *jsonData = [NSJSONSerialization dataWithJSONObject:contextArray options:0 error:&error];
        AIChatListMessageModel *lastMessage = [self.belongMessages lastObject];
        if (!error) {
            lastMessage.context = [[NSString alloc] initWithData:jsonData encoding:NSUTF8StringEncoding];
        }
        lastMessage.done = YES;
        // 上一条（用户消息）标记完成
        if (self.belongMessages.count >= 2) {
            self.belongMessages[self.belongMessages.count-2].done = YES;
        }
        if (self.onDoneUpdate) {
            NSString *finalText = [self stringByRemovingEmojis:lastMessage.text ?: @""];
            self.onDoneUpdate(contextArray, finalText);
        }

    });
    [self endBackgroundStreamingIfNeeded];
    return;
}

#pragma mark - Background streaming lifecycle

- (void)beginBackgroundStreamingIfNeeded {
    // 延长后台存活时间，避免切到后台时流式任务立即被挂起
    if (self.backgroundTaskId == UIBackgroundTaskInvalid) {
        __weak typeof(self) weakSelf = self;
        self.backgroundTaskId = [[UIApplication sharedApplication] beginBackgroundTaskWithName:@"AIStreaming" expirationHandler:^{
            __strong typeof(weakSelf) self = weakSelf;
            if (!self) return;
            // 到期仍未完成，主动取消以释放资源
            if (self.dataTask) {
                [self.dataTask cancel];
                self.dataTask = nil;
            }
            [self endBackgroundStreamingIfNeeded];
        }];
    }
}

- (void)endBackgroundStreamingIfNeeded {
    if (self.backgroundTaskId != UIBackgroundTaskInvalid) {
        UIBackgroundTaskIdentifier bid = self.backgroundTaskId;
        self.backgroundTaskId = UIBackgroundTaskInvalid;
        [[UIApplication sharedApplication] endBackgroundTask:bid];
    }
}


@end

