}

- (instancetype)initWithCoder:(NSCoder *)coder {
    self = [super initWithCoder:coder];
    if (self) {
        [self setup];
    }
    return self;
}

- (void)setup {
    _columnCount = 1;
    _columnSpacing = 10.0f;
    _itemSpacing = 10.0f;
    _sectionInset = UIEdgeInsetsMake(10, 10, 10, 10);
}

#pragma mark - 懒加载
- (NSMutableArray *)attributesArray {
    if (!_attributesArray) {
        _attributesArray = [NSMutableArray array];
    }
    return _attributesArray;
}

- (NSMutableArray *)columnHeights {
    if (!_columnHeights) {
        _columnHeights = [NSMutableArray array];
    }
    return _columnHeights;
}

- (NSMutableDictionary *)attributesCache {
    if (!_attributesCache) {
        _attributesCache = [NSMutableDictionary dictionary];
    }
    return _attributesCache;
}

#pragma mark - 重写布局方法
- (void)prepareLayout {
    [super prepareLayout];

    // 清空缓存
    [self.attributesCache removeAllObjects];
    [self.attributesArray removeAllObjects];
    [self.columnHeights removeAllObjects];
    self.contentHeight = 0;

    // 初始化每列高度
    for (NSInteger i = 0; i < self.columnCount; i++) {
        [self.columnHeights addObject:@(self.sectionInset.top)];
    }

    // 如果没有collectionView或代理，直接返回
    if (!self.collectionView || !self.delegate) {
        return;
    }

    // 计算每个item的布局属性[3,6](@ref)
    NSInteger itemCount = [self.collectionView numberOfItemsInSection:0];
    if (itemCount == 0) return;

    // 计算每列宽度
    CGFloat collectionViewWidth = CGRectGetWidth(self.collectionView.frame);
    CGFloat totalHorizontalSpacing = self.sectionInset.left + self.sectionInset.right +
                                   (self.columnCount - 1) * self.columnSpacing;
    CGFloat itemWidth = (collectionViewWidth - totalHorizontalSpacing) / self.columnCount;

    // 遍历所有item，计算布局属性[1,2](@ref)
    for (NSInteger i = 0; i < itemCount; i++) {
        NSIndexPath *indexPath = [NSIndexPath indexPathForItem:i inSection:0];

        // 通过代理获取item高度[3](@ref)
        CGFloat itemHeight = [self.delegate collectionView:self.collectionView
                                                    layout:self
                                    heightForItemAtIndexPath:indexPath];

        // 找到当前高度最小的列[1](@ref)
        NSInteger targetColumn = [self shortestColumnIndex];
        CGFloat xOffset = self.sectionInset.left + targetColumn * (itemWidth + self.columnSpacing);
        CGFloat yOffset = [self.columnHeights[targetColumn] floatValue];

        // 如果不是第一行，添加行间距
        if (yOffset != self.sectionInset.top) {
            yOffset += self.itemSpacing;
        }

        // 创建布局属性
        UICollectionViewLayoutAttributes *attributes =
            [UICollectionViewLayoutAttributes layoutAttributesForCellWithIndexPath:indexPath];
        attributes.frame = CGRectMake(xOffset, yOffset, itemWidth, itemHeight);

        [self.attributesArray addObject:attributes];
        self.attributesCache[indexPath] = attributes;

        // 更新该列高度
        CGFloat newHeight = yOffset + itemHeight;
        self.columnHeights[targetColumn] = @(newHeight);

        // 更新内容总高度
        if (newHeight > self.contentHeight) {
            self.contentHeight = newHeight;
        }
    }

    // 加上底部内边距
    self.contentHeight += self.sectionInset.bottom;
}

- (NSArray<UICollectionViewLayoutAttributes *> *)layoutAttributesForElementsInRect:(CGRect)rect {
    // 返回在给定矩形区域内的item的布局属性[6](@ref)
    NSMutableArray *visibleAttributes = [NSMutableArray array];

    for (UICollectionViewLayoutAttributes *attributes in self.attributesArray) {
        if (CGRectIntersectsRect(attributes.frame, rect)) {
            [visibleAttributes addObject:attributes];
        }
    }

    return visibleAttributes;
}

- (UICollectionViewLayoutAttributes *)layoutAttributesForItemAtIndexPath:(NSIndexPath *)indexPath {
    // 返回指定indexPath的布局属性[6](@ref)
    return self.attributesCache[indexPath];
}

- (CGSize)collectionViewContentSize {
    // 返回collectionView的内容大小[3](@ref)
    return CGSizeMake(CGRectGetWidth(self.collectionView.frame), self.contentHeight);
}

- (BOOL)shouldInvalidateLayoutForBoundsChange:(CGRect)newBounds {
    // 当bounds改变时是否重新布局[3](@ref)
    return !CGSizeEqualToSize(self.collectionView.bounds.size, newBounds.size);
}

#pragma mark - 辅助方法
- (NSInteger)shortestColumnIndex {
    // 找到当前高度最小的列[1,2](@ref)
    NSInteger shortestIndex = 0;
    CGFloat minHeight = CGFLOAT_MAX;

    for (NSInteger i = 0; i < self.columnCount; i++) {
        CGFloat currentHeight = [self.columnHeights[i] floatValue];
        if (currentHeight < minHeight) {
            minHeight = currentHeight;
            shortestIndex = i;
        }
    }

    return shortestIndex;
}

