        AIChatListMessageModel *g1 = [[AIChatListMessageModel alloc] initWithText:g1Text time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO];
//        AIChatListMessageModel *g2 = [[AIChatListMessageModel alloc] initWithText:g2Text time:[NSDate date] type:AIChatListMessageTypeSent context:@"" Done:NO];
        [msgs addObject:g1];
//        [msgs addObject:g2];
    }
    return msgs;
}

